CREATE TABLE IF NOT EXISTS t_p61016064_digital_innovation_i.wb_benchmarks (id SERIAL PRIMARY KEY, user_id INTEGER NOT NULL, title TEXT NOT NULL, source_name TEXT, source_url TEXT, industry TEXT, organization_name TEXT, benchmark_type TEXT NOT NULL DEFAULT 'digitalization', summary TEXT, what_was_done TEXT, observed_effect TEXT, applicability TEXT, confidence_level TEXT NOT NULL DEFAULT 'medium', limitations TEXT, notes TEXT, is_archived BOOLEAN NOT NULL DEFAULT FALSE, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()); CREATE INDEX IF NOT EXISTS idx_wb_bench_user ON t_p61016064_digital_innovation_i.wb_benchmarks(user_id);